import{_ as e,o as a,c as i,ag as n}from"./chunks/framework.BDReElpY.js";const p=JSON.parse('{"title":"Vex Silicon Native: Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"archive/silicon/overview.md","filePath":"archive/silicon/overview.md"}'),o={name:"archive/silicon/overview.md"};function l(r,t,s,d,c,g){return a(),i("div",null,[...t[0]||(t[0]=[n(`<h1 id="vex-silicon-native-introduction" tabindex="-1">Vex Silicon Native: Introduction <a class="header-anchor" href="#vex-silicon-native-introduction" aria-label="Permalink to &quot;Vex Silicon Native: Introduction&quot;">​</a></h1><blockquote><p><em><strong>&quot;Every Cycle, Every Core, Every Time&quot;</strong></em></p></blockquote><p>Vex is designed with a <strong>&quot;vector-first&quot;</strong> philosophy, aiming to eliminate the &quot;library hell&quot; of traditional high-performance computing. Instead of relying on external libraries like NumPy, PyTorch, or Eigen, Vex builds these capabilities directly into the language syntax and compiler.</p><h2 id="the-problem-library-hell" tabindex="-1">The Problem: Library Hell <a class="header-anchor" href="#the-problem-library-hell" aria-label="Permalink to &quot;The Problem: Library Hell&quot;">​</a></h2><p>In languages like Python or C++, high-performance computing often involves juggling multiple incompatible libraries:</p><ul><li><strong>Python:</strong> <code>numpy</code> vs <code>torch</code> vs <code>tensorflow</code> vs <code>jax</code>. Each has its own tensor types, memory management, and API. Moving data between them is costly and error-prone.</li><li><strong>C++:</strong> Manual memory management, complex template metaprogramming, and verbose intrinsic functions for SIMD/GPU usage.</li></ul><h2 id="the-vex-solution-native-vector-semantics" tabindex="-1">The Vex Solution: Native Vector Semantics <a class="header-anchor" href="#the-vex-solution-native-vector-semantics" aria-label="Permalink to &quot;The Vex Solution: Native Vector Semantics&quot;">​</a></h2><p>Vex introduces <strong>Vector Semantics</strong>, treating arrays and matrices as first-class citizens with built-in hardware acceleration.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Vex: Single Type, Single API</span></span>
<span class="line"><span>let a: [f32; 1024] = ...</span></span>
<span class="line"><span>let b = a + c          // Automatic SIMD or GPU offloading</span></span>
<span class="line"><span>let sum = \\+a          // Built-in reduction operator</span></span>
<span class="line"><span>let grad = @{ ... }    // Built-in autograd scope</span></span></code></pre></div><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ol><li><strong>Unified Tensor Strategy:</strong> No import needed. <code>[T; N]</code> implies vectorization potential.</li><li><strong>Automatic Offloading:</strong> The compiler decides whether to run on CPU (SIMD) or GPU based on data size and operation complexity.</li><li><strong>Language-Level Autograd:</strong> Derivative computation is a syntactic feature (<code>@{ ... }</code>), not a library wrapper.</li><li><strong>Rich Operator Set:</strong> Specialized operators for linear algebra (<code>&lt;*&gt;</code>), reductions (<code>\\+</code>), and signal processing eliminate verbose function calls.</li></ol><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">Python</th><th style="text-align:left;">C++</th><th style="text-align:left;">Rust</th><th style="text-align:left;">Vex</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>SIMD</strong></td><td style="text-align:left;">via NumPy</td><td style="text-align:left;">Intrinsics</td><td style="text-align:left;"><code>std::simd</code></td><td style="text-align:left;"><strong>Automatic</strong></td></tr><tr><td style="text-align:left;"><strong>GPU</strong></td><td style="text-align:left;">PyTorch/JAX</td><td style="text-align:left;">CUDA</td><td style="text-align:left;">wgpu/shaders</td><td style="text-align:left;"><strong>Automatic</strong></td></tr><tr><td style="text-align:left;"><strong>Autograd</strong></td><td style="text-align:left;">PyTorch</td><td style="text-align:left;">None</td><td style="text-align:left;">Libraries</td><td style="text-align:left;"><strong>Native <code>@{}</code></strong></td></tr><tr><td style="text-align:left;"><strong>Linear Alg</strong></td><td style="text-align:left;">SciPy</td><td style="text-align:left;">Eigen</td><td style="text-align:left;">nalgebra</td><td style="text-align:left;"><strong>Native <code>&lt;*&gt;</code></strong></td></tr></tbody></table><h2 id="vision" tabindex="-1">Vision <a class="header-anchor" href="#vision" aria-label="Permalink to &quot;Vision&quot;">​</a></h2><p>Vex aims to be the single language for the entire AI/HPC stack, from writing the kernel (replacing CUDA) to modelling the neural network (replacing Python).</p>`,15)])])}const u=e(o,[["render",l]]);export{p as __pageData,u as default};
